I have the same problem with dynamoDB.
Here's an example: 
`lambda_dynamodb.js`
```const AWS = require('aws-sdk');
const dynamoDB = new AWS.DynamoDB({
  region  : 'eu-west-1',
  endpoint: 'http://localhost:4569'
});
const documentClient = new AWS.DynamoDB.DocumentClient({service: dynamoDB});

module.exports.handler = (event, context, callback) => {
  let params = {
	TableName : 'local-test',
	Item: {id : 123, username : 'foo'}
  };

  documentClient.put(params).promise()
  .then((response) => {
  	callback(null, response);	
  })
  .catch(callback);

};
```

If I invoke it I get : 
```
{"errorMessage":"connect ECONNREFUSED 127.0.0.1:4569","errorType":"NetworkingError","stackTrace":["Object.exports._errnoException (util.js:1018:11)","exports._exceptionWithHostPort (util.js:1041:20)","TCPConnectWrap.afterConnect [as oncomplete] (net.js:1086:14)"]}
